import streamlit as st

def load_custom_css():
    st.markdown("""
    <style>
        /* Ana Arka Plan - Tamamen Beyaz ve Temiz */
        [data-testid="stAppViewContainer"] {
            background-color: #ffffff !important;
            background-image: none !important;
        }
        
        /* Sidebar Tasarımı */
        section[data-testid="stSidebar"] {
            background-color: #f8fafc !important;
            border-right: 1px solid #e2e8f0;
        }
        
        section[data-testid="stSidebar"] label,
        section[data-testid="stSidebar"] .stMarkdown p {
            color: #1e293b !important;
            font-weight: 600 !important;
        }

        /* Ana içerik alanı */
        .main .block-container {
            background-color: #ffffff;
            padding: 3rem;
            border-radius: 0;
            margin-top: 0;
            box-shadow: none;
        }

        /* Başlıklar */
        h1, h2, h3 {
            color: #0f172a !important;
            font-weight: 700 !important;
        }

        /* Kart Tasarımları */
        .metric-card {
            background: #ffffff !important;
            padding: 20px;
            border-radius: 12px;
            border: 1px solid #e2e8f0;
            box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05);
            text-align: center;
        }

        .metric-label {
            font-size: 0.85rem;
            color: #64748b;
            font-weight: 600;
        }

        .metric-value {
            font-size: 1.8rem;
            font-weight: 800;
            color: #1e40af;
        }
        
        .dss-subtext {
            font-size: 0.75rem !important;
            color: #64748b !important;
        }

        /* Input alanları */
        .stTextInput input, .stSelectbox div[data-baseweb="select"] {
            border-radius: 8px !important;
            border: 1px solid #cbd5e1 !important;
        }
    </style>
    """, unsafe_allow_html=True)

def render_header():
    st.markdown(f"""
    <div style="text-align: center; margin-bottom: 2rem;">
        <img src="data:image/png;base64," style="width: 250px; margin-bottom: 1rem;">
        <h1 style="color: #0f172a; font-size: 2.2rem; margin-top: 0; font-weight: 800;">STRATEJİK PMS</h1>
        <p style="color: #64748b; font-size: 1.1rem; font-weight: 500;">Yapay Zeka Destekli Yeni Nesil Performans Yönetimi</p>
        <hr style="border: 0; height: 1px; background: #e2e8f0; margin: 2rem 0;">
    </div>
    """, unsafe_allow_html=True)

def display_chat_message(role, message):
    if role == "user":
        st.markdown(f'<div class="user-message">👤 <b>Siz:</b><br>{message}</div>', unsafe_allow_html=True)
    else:
        # Markdown içeriğini desteklemek için st.markdown içinde HTML kullanımı bazen sorun olabilir
        # Ama basit metinler için sorun yok. Karmaşık markdown için st.chat_message daha iyi olabilir.
        # Biz burada HTML container içinde markdown render edemeyiz kolayca.
        # O yüzden hibrit bir yapı kullanacağız.
        st.markdown(f'<div class="bot-message">🤖 <b>Asistan:</b><br>{message}</div>', unsafe_allow_html=True)
